def allocate(stock: dict[str, int], order: dict[str, int]) -> dict[str, int]:
    # Проверяем наличие всех SKU и достаточный остаток без мутации входного словаря
    allocation: dict[str, int] = {}
    for sku, qty in order.items():
        if sku not in stock:
            raise ValueError(f"SKU {sku} не найден в наличии")
        available = stock[sku]
        if available < qty:
            raise ValueError(f"Недостаточно остатка для SKU {sku}: запрошено {qty}, доступно {available}")
        allocation[sku] = qty
    return allocation

